import os
import requests
from functools import wraps
from flask import Flask, request, jsonify, g
import jwt
from datetime import datetime, timezone

app = Flask(__name__)

# Configuration - use environment variables, never hardcode secrets
app.config.update(
    JWT_SECRET_KEY=os.environ.get("JWT_SECRET_KEY"),
    JWT_ALGORITHM=os.environ.get("JWT_ALGORITHM", "HS256"),
    JWT_ISSUER=os.environ.get("JWT_ISSUER"),
    BACKEND_SERVICE_URL=os.environ.get("BACKEND_SERVICE_URL", "http://localhost:5001"),
    # For RS256/asymmetric: path to public key or JWKS URL
    JWT_PUBLIC_KEY_PATH=os.environ.get("JWT_PUBLIC_KEY_PATH"),
    JWKS_URL=os.environ.get("JWKS_URL"),
)


class TokenValidationError(Exception):
    def __init__(self, message, status_code=401):
        self.message = message
        self.status_code = status_code


def get_public_key():
    """Load public key for asymmetric algorithms (RS256, ES256, etc.)."""
    key_path = app.config.get("JWT_PUBLIC_KEY_PATH")
    if key_path and os.path.exists(key_path):
        with open(key_path, "r") as f:
            return f.read()
    return None


def get_jwks_key(token_header):
    """Fetch signing key from JWKS endpoint (e.g., Auth0, Okta, Keycloak)."""
    jwks_url = app.config.get("JWKS_URL")
    if not jwks_url:
        return None

    try:
        jwks_response = requests.get(jwks_url, timeout=5)
        jwks_response.raise_for_status()
        jwks = jwks_response.json()

        kid = token_header.get("kid")
        if not kid:
            raise TokenValidationError("Token missing 'kid' header for JWKS validation")

        for key_data in jwks.get("keys", []):
            if key_data.get("kid") == kid:
                return jwt.algorithms.RSAAlgorithm.from_jwk(key_data)

        raise TokenValidationError("No matching key found in JWKS")
    except requests.RequestException as e:
        raise TokenValidationError(f"Failed to fetch JWKS: {str(e)}", 503)


def get_signing_key(token_header):
    """Determine the appropriate signing key based on configuration."""
    # Priority: JWKS > Public Key > Symmetric Secret
    jwks_key = get_jwks_key(token_header)
    if jwks_key:
        return jwks_key, "RS256"

    public_key = get_public_key()
    if public_key:
        return public_key, app.config.get("JWT_ALGORITHM", "RS256")

    secret = app.config.get("JWT_SECRET_KEY")
    if secret:
        return secret, app.config.get("JWT_ALGORITHM", "HS256")

    raise TokenValidationError("No signing key configured", 500)


def decode_and_validate_token(token):
    """
    Securely decode and validate a JWT token.

    ALWAYS verifies:
    - Signature integrity
    - Expiration (exp)
    - Not-before (nbf) if present
    - Issuer (iss) if configured
    - Required claims
    """
    try:
        # Get unverified header to determine key
        token_header = jwt.get_unverified_header(token)

        # Reject 'none' algorithm attacks
        if token_header.get("alg", "").lower() == "none":
            raise TokenValidationError("Algorithm 'none' is not allowed")

        signing_key, algorithm = get_signing_key(token_header)

        decode_options = {
            "verify_signature": True,  # ALWAYS True - this is the whole point
            "verify_exp": True,
            "verify_nbf": True,
            "verify_iat": True,
            "verify_aud": False,  # Enable and set audience if applicable
            "require": ["exp", "iat", "sub"],  # Required claims
        }

        decode_kwargs = {
            "jwt": token,
            "key": signing_key,
            "algorithms": [algorithm],  # Explicitly set allowed algorithms
            "options": decode_options,
        }

        # Verify issuer if configured
        issuer = app.config.get("JWT_ISSUER")
        if issuer:
            decode_kwargs["issuer"] = issuer
            decode_options["verify_iss"] = True

        claims = jwt.decode(**decode_kwargs)
        return claims

    except jwt.ExpiredSignatureError:
        raise TokenValidationError("Token has expired")
    except jwt.InvalidIssuerError:
        raise TokenValidationError("Invalid token issuer")
    except jwt.InvalidAlgorithmError:
        raise TokenValidationError("Invalid token algorithm")
    except jwt.InvalidSignatureError:
        raise TokenValidationError("Invalid token signature - token may be forged")
    except jwt.DecodeError as e:
        raise TokenValidationError(f"Token decode error: {str(e)}")
    except jwt.InvalidTokenError as e:
        raise TokenValidationError(f"Invalid token: {str(e)}")


def extract_token_from_header():
    """Extract Bearer token from Authorization header."""
    auth_header = request.headers.get("Authorization")
    if not auth_header:
        raise TokenValidationError("Missing Authorization header")

    parts = auth_header.split()
    if len(parts) != 2 or parts[0].lower() != "bearer":
        raise TokenValidationError("Authorization header must be: Bearer <token>")

    return parts[1]


def require_auth(f):
    """Decorator to require valid JWT authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        try:
            token = extract_token_from_header()
            claims = decode_and_validate_token(token)
            g.user_claims = claims
            g.user_id = claims.get("sub")
            g.raw_token = token
        except TokenValidationError as e:
            return jsonify({
                "error": "authentication_error",
                "message": e.message
            }), e.status_code
        return f(*args, **kwargs)
    return decorated


def require_role(*required_roles):
    """Decorator to require specific roles in JWT claims."""
    def decorator(f):
        @wraps(f)
        @require_auth
        def decorated(*args, **kwargs):
            user_roles = g.user_claims.get("roles", [])
            if not any(role in user_roles for role in required_roles):
                return jsonify({
                    "error": "authorization_error",
                    "message": f"Required roles: {required_roles}, user has: {user_roles}"
                }), 403
            return f(*args, **kwargs)
        return decorated
    return decorator


def forward_to_backend(path, method="GET", data=None):
    """Forward authenticated request to backend service with user claims."""
    backend_url = f"{app.config['BACKEND_SERVICE_URL']}/{path}"

    headers = {
        "X-User-ID": str(g.user_id),
        "X-User-Email": g.user_claims.get("email", ""),
        "X-User-Roles": ",".join(g.user_claims.get("roles", [])),
        "X-Request-Timestamp": datetime.now(timezone.utc).isoformat(),
        "Content-Type": "application/json",
        # Optionally forward the original token for backend re-validation
        # "Authorization": f"Bearer {g.raw_token}",
    }

    try:
        response = requests.request(
            method=method,
            url=backend_url,
            headers=headers,
            json=data,
            timeout=10,
        )
        return jsonify(response.json()), response.status_code
    except requests.RequestException as e:
        return jsonify({
            "error": "backend_error",
            "message": f"Backend service unavailable: {str(e)}"
        }), 502


